// ── Clean, normalize, score every scraped listing ──────────────────
// Paste of scoring/phoneNormalize.js + scoring/leadScoring.js (trimmed).

function normalizeUaePhone(raw){ if(!raw) return ''; let d=String(raw).replace(/[^\d]/g,''); if(d.startsWith('00971'))d=d.slice(5); else if(d.startsWith('971'))d=d.slice(3); else if(d.startsWith('0'))d=d.slice(1); if(d.length===9&&d.startsWith('5'))return '+971'+d; const l=d.slice(-9); if(l.length===9&&l.startsWith('5'))return '+971'+l; return ''; }
function looksLikeAgency(name){ if(!name) return false; return /(real\s?estate|properties|property|broker|realty|consultanc|llc|homes|estate agent)/i.test(String(name)); }
const TARGET=['nuaimiya','rashidiya','rumailah','rawda','jurf','mowaihat','hamidiya'];
function tier(s){ return s>=8?'HOT':s>=5?'WARM':'COLD'; }
function clamp(n,a,b){ return Math.max(a,Math.min(b,n)); }
function score(l){ const r=[]; let s=4; const area=String(l.area||'').toLowerCase(); const inTarget=TARGET.some(a=>area.includes(a));
  if(l.listingAgeDays>=60){s+=2;r.push('Sitting 60+ days');} else if(l.listingAgeDays>=30){s+=1.5;r.push('Listed 30+ days');} else if(l.listingAgeDays<3){s-=1.5;r.push('Brand-new (<3d)');}
  if(l.listingsCount>=4){s+=2;r.push(l.listingsCount+' listings (portfolio)');} else if(l.listingsCount>=2){s+=1.5;r.push(l.listingsCount+' listings (multi)');}
  if(l.isWholeProperty&&l.propertyType==='building'){s+=2;r.push('Whole building');} else if(l.isWholeProperty&&l.propertyType==='villa'){s+=1.5;r.push('Whole villa');} else if(l.propertyType==='unit'){s-=1;r.push('Single unit');}
  if(l.isDirectOwner===true){s+=1.5;r.push('Direct owner');} else if(l.isDirectOwner===false){s-=2;r.push('Agency');}
  if(inTarget){s+=1.5;r.push('Target area: '+l.area);} else if(area){s-=1;r.push('Outside target');}
  s=clamp(Math.round(s),1,10); return {score:s,tier:tier(s),reason:r.join('; ')}; }

const out=[];
for (const item of $input.all()) {
  const d = item.json;
  const phone = normalizeUaePhone(d.phone || d.contactPhone || d.phoneNumber || (d.contactInfo&&d.contactInfo.phone));
  if (!phone) continue;                       // phone is mandatory
  const title = (d.title||'') + ' ' + (d.description||'');
  const isWhole = /whole|full building|entire|كامل|بناية كاملة|whole villa/i.test(title) || /building|villa/i.test(d.propertyType||'');
  const ptype = /building/i.test(d.propertyType||title)?'building': /villa/i.test(d.propertyType||title)?'villa': /land/i.test(d.propertyType||title)?'land':'unit';
  const agentName = d.agentName || d.contactName || (d.agency&&d.agency.name) || '';
  const ageDays = d.listingAgeDays != null ? d.listingAgeDays : (d.createdAt ? Math.floor((Date.now()-new Date(d.createdAt))/86400000) : 0);
  const lead = {
    phone,
    ownerName: looksLikeAgency(agentName)? '' : agentName,
    area: d.location || d.area || d.neighbourhood || '',
    propertyType: ptype,
    isWholeProperty: !!isWhole,
    isDirectOwner: !looksLikeAgency(agentName),
    listingAgeDays: ageDays,
    listingsCount: 1,
    source: 'dubizzle',
    listingUrl: d.url || d.listingUrl || '',
    price: d.price || '',
    seenDate: new Date().toISOString().slice(0,10),
  };
  const sc = score(lead);
  out.push({ json: { ...lead, leadScore: sc.score, tier: sc.tier, aiNotes: sc.reason } });
}
return out;
